<script setup lang="ts">
import {computed,onMounted,reactive,ref} from 'vue';import {api,type Envelope} from '@/api';import {ElMessage} from 'element-plus';import {useAuthStore} from '@/stores/auth';
const auth=useAuthStore(),employee=computed(()=>auth.user?.role==='EMPLOYEE'),canManage=computed(()=>auth.can('course:manage')),canAttendance=computed(()=>auth.can('attendance:manage'));const courses=ref<any[]>([]),sessions=ref<any[]>([]),attendance=ref<any[]>([]),employees=ref<any[]>([]),code=ref('');const course=reactive({name:'',description:''}),session=reactive<any>({courseId:null,title:'',location:'',hours:1,startsAt:'',endsAt:'',checkinStartsAt:'',checkinEndsAt:''}),manual=reactive<any>({sessionId:null,employeeId:null,remark:''});
async function load(){courses.value=(await api.get<any,Envelope<any[]>>('/courses')).data;sessions.value=(await api.get<any,Envelope<any[]>>('/sessions')).data;attendance.value=(await api.get<any,Envelope<any[]>>('/attendance')).data;if(canAttendance.value)employees.value=(await api.get<any,Envelope<any>>('/employees',{params:{size:100}})).data.records}async function createCourse(){await api.post('/courses',course);ElMessage.success('课程已创建');load()}async function createSession(){const r=await api.post<any,Envelope<any>>('/sessions',session);ElMessage.success(`签到码：${r.data.checkinCode}`);load()}async function checkin(){await api.post('/attendance/checkin',{code:code.value});ElMessage.success('签到成功');load()}async function addManual(){await api.post('/attendance/manual',manual);ElMessage.success('补录成功');load()}onMounted(load);
</script>
<template><div class="page"><div class="page-head"><h2>课程与签到</h2></div><el-card v-if="employee"><div class="toolbar"><el-input v-model="code" maxlength="6" placeholder="6位签到码"/><el-button type="primary" @click="checkin">签到</el-button></div></el-card><el-row v-if="canManage" :gutter="16"><el-col :md="8"><el-card><template #header>创建课程</template><el-input v-model="course.name" placeholder="课程名称"/><el-input v-model="course.description" type="textarea" placeholder="说明"/><el-button type="primary" @click="createCourse">创建</el-button></el-card></el-col><el-col :md="16"><el-card><template #header>开设场次</template><div class="form-grid"><el-select v-model="session.courseId" placeholder="课程"><el-option v-for="x in courses" :key="x.id" :label="x.name" :value="x.id"/></el-select><el-input v-model="session.title" placeholder="场次"/><el-date-picker v-model="session.startsAt" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/><el-date-picker v-model="session.endsAt" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/><el-date-picker v-model="session.checkinStartsAt" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/><el-date-picker v-model="session.checkinEndsAt" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></div><el-button type="primary" @click="createSession">创建场次</el-button></el-card></el-col></el-row><el-card v-if="canAttendance"><template #header>签到补录</template><div class="toolbar"><el-select v-model="manual.sessionId"><el-option v-for="x in sessions" :key="x.id" :label="x.title" :value="x.id"/></el-select><el-select v-model="manual.employeeId" filterable><el-option v-for="x in employees" :key="x.id" :label="x.name" :value="x.id"/></el-select><el-input v-model="manual.remark"/><el-button @click="addManual">补录</el-button></div></el-card><el-card><template #header>学习记录</template><el-table :data="attendance"><el-table-column prop="employee_name" label="员工"/><el-table-column prop="course_name" label="课程"/><el-table-column prop="session_title" label="场次"/><el-table-column prop="status" label="状态"/><el-table-column prop="checked_at" label="签到时间"/></el-table></el-card><el-card><template #header>课程场次</template><el-table :data="sessions"><el-table-column prop="course_name" label="课程"/><el-table-column prop="title" label="场次"/><el-table-column prop="starts_at" label="开始"/><el-table-column v-if="canManage" prop="checkin_code" label="签到码"/></el-table></el-card></div></template>
